class Solution {
public:
    int countLargestGroup(int n) {
        std::unordered_map<int, int> sumCounts;
        for (int i = 1; i <= n; ++i) {
            int current = i;
            int sum = 0;
            while (current > 0) {
                sum += current % 10;
                current /= 10;
            }
            sumCounts[sum]++;
        }
        int maxSize = 0;
        for (const auto& pair : sumCounts) {
            if (pair.second > maxSize) {
                maxSize = pair.second;
            }
        }
        int result = 0;
        for (const auto& pair : sumCounts) {
            if (pair.second == maxSize) {
                ++result;
            }
        }
        return result;
    }
};

